#include<bits/stdc++.h>
using namespace std;
int dx[4]={1,2};
long long num=0;
int m,n,x,y,a,b,c,d;
int flag=0;
void dfs(int p)
{
	for(int i=0;i<=1;i++)
	{
		x=p+dx[i];
		if(x>=0&&x<=n)
		{
			if(x==n)
			{
				num++;
				return; 
			}
			dfs(x);
		}
	}
	return;
}
int main()
{
	scanf("%d%d",&m,&n);	
	dfs(m);
	printf("%lld",num);
	return 0;
}
